import React, { useEffect, useState } from "react";
import axios from "axios";
import "./Landing.css";
import toast from "react-hot-toast";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../Context/AuthContext";

const Landing = () => {
    // const [theme, setTheme] = useState("dark-purple");
    const [activeTab, setActiveTab] = useState("login");
    const { isAuthenticated, setIsAuthenticated, theme, setTheme } = useAuth();
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    useEffect(() => {
    if (isAuthenticated) {
            navigate("/dashboard", { replace: true });
        }
    }, [isAuthenticated, navigate]);
    const [loginData, setLoginData] = useState({
        identifier: "",
        password: ""
    });
    
    const [registerData, setRegisterData] = useState({
        username: "",
        email: "",
        password: ""
    });
    
    useEffect(() => {
        const savedTheme =
            localStorage.getItem("theme") || "dark-purple";

        setTheme(savedTheme);
    }, [setTheme]);

    useEffect(() => {
        document.documentElement.setAttribute(
            "data-theme",
            theme
        );

        localStorage.setItem("theme", theme);
    }, [theme]);

    const toggleTheme = () => {
        setTheme(prev =>
            prev === "dark-purple"
                ? "lavender"
                : "dark-purple"
        );
    };

    const handleLoginChange = (e) => {
        setLoginData({
            ...loginData,
            [e.target.name]: e.target.value
        });
    };

    const handleRegisterChange = (e) => {
        setRegisterData({
            ...registerData,
            [e.target.name]: e.target.value
        });
    };

    const handleLoginSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const payload = {
                password: loginData.password
            };

            if (loginData.identifier.includes("@")) {
                payload.email = loginData.identifier;
            } else {
                payload.username = loginData.identifier;
            }

            const response = await axios.post(
                "http://localhost:5000/api/auth/login",
                payload,
                {
                    withCredentials: true
                }
            );
            
            console.log(response.data.message);
            if (response.status === 200) {
                setIsAuthenticated(true);
                navigate("/dashboard");
            }
            // navigate("/dashboard")
        } catch (error) {
            console.log(
                error.response?.data?.message ||
                "Login failed"
            );
            if (error.response?.status === 403) {
                const userEmail = error.response?.data?.user?.email;
                await axios.post(
                    "http://localhost:5000/api/auth/send-otp",
                    {
                        email: userEmail,
                        purpose: "register"
                    },
                    {
                        withCredentials: true
                    }
                )
                navigate("/verify-otp", {
                    state: {
                        email: userEmail
                    }
                });
            }
        } finally {
            setLoading(false);
        }
    };

    const handleRegisterSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            const response = await axios.post(
                "http://localhost:5000/api/auth/register",
                registerData,
                {
                    withCredentials: true
                }
            );

            const userEmail = response?.data?.user?.email;

            if (response.status === 201) {
                await axios.post(
                    "http://localhost:5000/api/auth/send-otp",
                    {
                        email: userEmail,
                        purpose: "register"
                    },
                    {
                        withCredentials: true
                    }
                )
                navigate("/verify-otp", {
                    state: {
                        email: userEmail
                    }
                });
            }

        } catch (error) {
            console.log(
                error.response?.data?.message ||
                "Registration failed"
            );
        } finally {
            setLoading(false);
        }
    };

    return (
        <>
            {/* Navbar */}
            <header>
                <div className="container nav-wrapper">
                    <div className="landing-logo"></div>

                    <div className="nav-right">
                        <button
                            className="btn-theme"
                            id="themeToggle"
                            onClick={toggleTheme}
                        >
                            {
                                theme === "dark-purple"
                                    ? "✨ Light Mode"
                                    : "🔮 Dark Mode"
                            }
                        </button>

                        <a
                            href="#authSection"
                            onClick={() => setActiveTab("login")}
                            className="btn btn-secondary"
                            style={{
                                padding: "8px 16px",
                                fontSize: "0.85rem"
                            }}
                        >
                            Sign In
                        </a>
                    </div>
                </div>
            </header>

            {/* Hero Section */}
            <section className="hero">
                <div className="container">
                    <h1>
                        Track every rupee. Understand your spending.
                        Build better <span>financial habits</span>.
                    </h1>

                    <div className="hero-actions">
                        <a
                            href="#authSection"
                            className="btn btn-primary"
                            onClick={() => setActiveTab("register")}
                        >
                            Get Started
                        </a>
                    </div>
                </div>
            </section>

            {/* Auth Section */}
            <section
                className="auth-cta-section"
                id="authSection"
            >
                <div className="container">
                    <h2>Ready to take control?</h2>

                    <p
                        style={{
                            color: "var(--text-muted)"
                        }}
                    >
                        Create a free account or log back
                        into your dashboard below.
                    </p>

                    <div className="auth-container">

                        <div className="auth-tabs">
                            <button
                                className={`tab-btn ${
                                    activeTab === "login"
                                        ? "active"
                                        : ""
                                }`}
                                id="loginTab"
                                onClick={() =>
                                    setActiveTab("login")
                                }
                                disabled={loading}
                            >
                                Login
                            </button>

                            <button
                                className={`tab-btn ${
                                    activeTab === "register"
                                        ? "active"
                                        : ""
                                }`}
                                id="registerTab"
                                onClick={() =>
                                    setActiveTab("register")
                                }
                                disabled={loading}
                            >
                                Register
                            </button>
                        </div>

                        {/* Login Form */}
                        <form
                            id="loginForm"
                            className={`auth-form ${
                                activeTab === "login"
                                    ? "active"
                                    : ""
                            }`}
                            onSubmit={handleLoginSubmit}
                        >
                            <div className="input-group">
                                <label htmlFor="login-user">
                                    Username or Email
                                </label>

                                <input
                                    type="text"
                                    id="login-user"
                                    name="identifier"
                                    value={loginData.identifier}
                                    onChange={handleLoginChange}
                                    placeholder="Enter username or email"
                                    required
                                />
                            </div>

                            <div className="input-group">
                                <label htmlFor="login-pass">
                                    Password
                                </label>

                                <input
                                    type="password"
                                    id="login-pass"
                                    name="password"
                                    value={loginData.password}
                                    onChange={handleLoginChange}
                                    placeholder="••••••••"
                                    required
                                />
                            </div>

                            <button
                                type="submit"
                                className="form-btn"
                                disabled={loading}
                            >
                                { loading? "Signing In..." : "Log In" }
                            </button>
                        </form>

                        {/* Register Form */}
                        <form
                            id="registerForm"
                            className={`auth-form ${
                                activeTab === "register"
                                    ? "active"
                                    : ""
                            }`}
                            onSubmit={handleRegisterSubmit}
                        >
                            <div className="input-group">
                                <label htmlFor="reg-username">
                                    Username
                                </label>

                                <input
                                    type="text"
                                    id="reg-username"
                                    name="username"
                                    value={registerData.username}
                                    onChange={
                                        handleRegisterChange
                                    }
                                    placeholder="Choose a unique username"
                                    required
                                />
                            </div>

                            <div className="input-group">
                                <label htmlFor="reg-email">
                                    Email Address
                                </label>

                                <input
                                    type="email"
                                    id="reg-email"
                                    name="email"
                                    value={registerData.email}
                                    onChange={
                                        handleRegisterChange
                                    }
                                    placeholder="name@example.com"
                                    required
                                />
                            </div>

                            <div className="input-group">
                                <label htmlFor="reg-pass">
                                    Password
                                </label>

                                <input
                                    type="password"
                                    id="reg-pass"
                                    name="password"
                                    value={registerData.password}
                                    onChange={
                                        handleRegisterChange
                                    }
                                    placeholder="Create strong password"
                                    required
                                />
                            </div>

                            <button
                                type="submit"
                                className="form-btn"
                                disabled={loading}
                            >
                                { loading? "Creating Account..." : "Create Account" }
                            </button>
                        </form>

                    </div>
                </div>
            </section>
        </>
    );
};

export default Landing;
